        <h3 id="modalTitle">Customer Details</h3>
        <div id="modalBody">Loading...</div>
    </div>
</div>

<script>
// Donut chart
(function(){
    var tiers = @Html.Raw(Newtonsoft.Json.JsonConvert.SerializeObject(Model.TierBreakdown));
    var canvas = document.getElementById('donutChart');
    var ctx = canvas.getContext('2d');
    canvas.width = canvas.offsetWidth * 2; canvas.height = 520;
    var cx = canvas.width/2, cy = canvas.height/2, r = Math.min(cx,cy)-40, ri = r*0.55;
    var total = 0; tiers.forEach(function(t){total += t.TotalClv;});
    if(total===0) total=1;
    var angle = -Math.PI/2;
    tiers.forEach(function(t){
        var slice = (t.TotalClv/total)*Math.PI*2;
        ctx.beginPath(); ctx.moveTo(cx,cy); ctx.arc(cx,cy,r,angle,angle+slice); ctx.closePath();
        ctx.fillStyle = t.Color; ctx.fill();
        // label
        var mid = angle+slice/2;
        var lx = cx+Math.cos(mid)*(r+ri)/2, ly = cy+Math.sin(mid)*(r+ri)/2;
        ctx.fillStyle='#fff'; ctx.font='bold '+(canvas.width>600?'24':'18')+'px sans-serif'; ctx.textAlign='center'; ctx.textBaseline='middle';
        if(t.RevenueShare > 5) ctx.fillText(t.RevenueShare.toFixed(0)+'%', lx, ly);
        angle += slice;
    });
    // Inner circle
    ctx.beginPath(); ctx.arc(cx,cy,ri,0,Math.PI*2); ctx.fillStyle='#192734'; ctx.fill();
    ctx.fillStyle='#fff'; ctx.font='bold 28px sans-serif'; ctx.textAlign='center'; ctx.textBaseline='middle';
    ctx.fillText(tiers.reduce(function(s,t){return s+t.Count;},0)+' customers', cx, cy);
    // Legend
    var ly2 = canvas.height - 20;
    var lx2 = 20;
    tiers.forEach(function(t){
        ctx.fillStyle=t.Color; ctx.fillRect(lx2,ly2-12,16,16); ctx.fillStyle='#8899a6';
        ctx.font='22px sans-serif'; ctx.textAlign='left'; ctx.fillText(t.Tier+' ('+t.Count+')',lx2+22,ly2);
        lx2 += 160;
    });
})();

// Trend chart
(function(){
    var trend = @Html.Raw(Newtonsoft.Json.JsonConvert.SerializeObject(Model.Trend));
    var canvas = document.getElementById('trendChart');
    var ctx = canvas.getContext('2d');
    canvas.width = canvas.offsetWidth * 2; canvas.height = 520;
    var pad = {t:30,r:20,b:50,l:70};
    var w = canvas.width-pad.l-pad.r, h = canvas.height-pad.t-pad.b;
    var n = trend.Labels.length; if(n<2) return;
    var allVals = trend.AvgClvOverTime.concat(trend.NewCustomerClv);
    var maxV = Math.max.apply(null, allVals)||1;
    function x(i){return pad.l + (i/(n-1))*w;}
    function y(v){return pad.t + h - (v/maxV)*h;}
    // Grid
    ctx.strokeStyle='#2d3741'; ctx.lineWidth=1;
    for(var g=0;g<=4;g++){var gy=pad.t+(h/4)*g; ctx.beginPath();ctx.moveTo(pad.l,gy);ctx.lineTo(pad.l+w,gy);ctx.stroke();
        ctx.fillStyle='#657786';ctx.font='20px sans-serif';ctx.textAlign='right';ctx.fillText('$'+(maxV-maxV/4*g).toFixed(0),pad.l-8,gy+6);}
    // Labels
    trend.Labels.forEach(function(l,i){ctx.fillStyle='#657786';ctx.font='20px sans-serif';ctx.textAlign='center';ctx.fillText(l,x(i),canvas.height-16);});
    // Lines
    function drawLine(data,color){ctx.beginPath();ctx.strokeStyle=color;ctx.lineWidth=3;
        data.forEach(function(v,i){i===0?ctx.moveTo(x(i),y(v)):ctx.lineTo(x(i),y(v));});ctx.stroke();
        data.forEach(function(v,i){ctx.beginPath();ctx.arc(x(i),y(v),5,0,Math.PI*2);ctx.fillStyle=color;ctx.fill();});}
    drawLine(trend.AvgClvOverTime,'#1da1f2');
    drawLine(trend.NewCustomerClv,'#17bf63');
    // Legend
    ctx.fillStyle='#1da1f2';ctx.fillRect(pad.l,8,14,14);ctx.fillStyle='#8899a6';ctx.font='20px sans-serif';ctx.textAlign='left';ctx.fillText('Avg CLV',pad.l+20,21);
    ctx.fillStyle='#17bf63';ctx.fillRect(pad.l+140,8,14,14);ctx.fillStyle='#8899a6';ctx.fillText('New Customer CLV',pad.l+160,21);
})();

// Table sort
var sortDir={};
function sortTable(col){
    var table=document.getElementById('topTable'), tbody=table.tBodies[0];
    var rows=Array.from(tbody.rows);
    sortDir[col]=!sortDir[col];
    rows.sort(function(a,b){
        var va=a.cells[col].innerText.replace(/[$,%]/g,''), vb=b.cells[col].innerText.replace(/[$,%]/g,'');
        var na=parseFloat(va),nb=parseFloat(vb);
        if(!isNaN(na)&&!isNaN(nb)) return sortDir[col]?na-nb:nb-na;
        return sortDir[col]?va.localeCompare(vb):vb.localeCompare(va);
    });
    rows.forEach(function(r){tbody.appendChild(r);});
}

// Customer detail modal
function showCustomer(id){
    document.getElementById('modal').classList.add('active');
    document.getElementById('modalBody').innerHTML='Loading...';
    fetch('/CustomerLifetimeValue/Customer/'+id).then(function(r){return r.json();}).then(function(d){
        if(!d.success){document.getElementById('modalBody').innerHTML='<p style="color:#e0245e">'+d.error+'</p>';return;}
        var p=d.profile;
        document.getElementById('modalTitle')='💎 '+p.Name;
        var html='<div class="detail-row"><span class="dl">Tier</span><span class="tier-badge tier-'+p.Tier+'">'+p.Tier+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Estimated CLV</span><span>$'+p.EstimatedClv.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Historical Revenue</span><span>$'+p.HistoricalRevenue.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Predicted Future</span><span>$'+p.PredictedFutureRevenue.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Total Rentals</span><span>'+p.TotalRentals+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Avg Monthly Spend</span><span>$'+p.AvgMonthlySpend.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Months Active</span><span>'+p.MonthsActive+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Membership</span><span>'+p.Membership+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Trajectory</span><span class="traj traj-'+p.Trajectory+'">'+(p.Trajectory==='Rising'?'↗':p.Trajectory==='Declining'?'↘':'→')+' '+p.Trajectory+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Retention Probability</span><span>'+p.RetentionProbability+'%</span></div>';
        html+='<div style="margin-top:10px"><span class="dl">Value Drivers</span><div style="margin-top:4px">';
        p.ValueDrivers.forEach(function(d){html+='<span class="driver-tag">'+d+'</span>';});
        html+='</div></div>';
        document.getElementById('modalTitle').textContent='💎 '+p.Name;
        document.getElementById('modalBody').innerHTML=html;
    }).catch(function(){document.getElementById('modalBody').innerHTML='<p style="color:#e0245e">Failed to load</p>';});
}
function closeModal(){document.getElementById('modal').classList.remove('active');}
</script>
</body>
</html>

