        html+='<div class="detail-row"><span class="dl">Historical Revenue</span><span>$'+p.HistoricalRevenue.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Predicted Future</span><span>$'+p.PredictedFutureRevenue.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Total Rentals</span><span>'+p.TotalRentals+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Avg Monthly Spend</span><span>$'+p.AvgMonthlySpend.toFixed(2)+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Months Active</span><span>'+p.MonthsActive+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Membership</span><span>'+p.Membership+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Trajectory</span><span class="traj traj-'+p.Trajectory+'">'+(p.Trajectory==='Rising'?'↗':p.Trajectory==='Declining'?'↘':'→')+' '+p.Trajectory+'</span></div>';
        html+='<div class="detail-row"><span class="dl">Retention Probability</span><span>'+p.RetentionProbability+'%</span></div>';
        html+='<div style="margin-top:10px"><span class="dl">Value Drivers</span><div style="margin-top:4px">';
