                            <span class="badge">@movie.ReservationQueueLength</span>
                        }
                        else
                        {
                            <text>—</text>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (Model.Movies.Count == 0)
    {
        <div class="alert alert-info">No movies match your filters.</div>
    }
}
else
{
    @* ── Calendar View ─── *@
    <div class="row">
        @foreach (var day in Model.Calendar)
        {
            var panelClass = day.IsToday ? "panel-primary"
                : day.EventCount > 0 ? "panel-info"
                : "panel-default";
            <div class="col-md-2 col-sm-3 col-xs-6" style="margin-bottom: 10px;">
                <div class="panel @panelClass">
                    <div class="panel-heading" style="padding: 5px 10px;">
                        <strong>@day.Date.ToString("ddd")</strong>
                        <span class="pull-right">@day.Date.ToString("MMM d")</span>
                    </div>
                    <div class="panel-body" style="padding: 8px; min-height: 80px;">
                        @if (day.EventCount == 0)
                        {
                            <small class="text-muted">No returns</small>
                        }
                        else
                        {
                            foreach (var evt in day.ReturningMovies)
                            {
                                <div style="margin-bottom: 4px;">
                                    <span class="glyphicon glyphicon-film" style="color: #337ab7;"></span>
                                    <small>@evt.MovieName</small>
                                </div>
                            }
                            foreach (var evt in day.ExpiringReservations)
                            {
                                <div style="margin-bottom: 4px;">
                                    <span class="glyphicon glyphicon-time" style="color: #f0ad4e;"></span>
                                    <small>@evt.MovieName</small>
                                </div>
                            }
                        }
                    </div>
                    @if (day.EventCount > 0)
                    {
                        <div class="panel-footer" style="padding: 3px 10px;">
                            <small>@day.EventCount event(s)</small>
                        </div>
                    }
                </div>
            </div>
        }
    </div>
}

<div style="margin-top: 20px;">
    @Html.ActionLink("← Coming Soon", "ComingSoon", null, new { @class = "btn btn-info" })
    @Html.ActionLink("Back to Movies", "Index", "Movies", null, new { @class = "btn btn-default" })
</div>

